function weakPaymentCustomerName(v){v=String(v||'').trim();return !v||v==='Clover payment'||v==='Unmatched Clover payment'||v==='Unknown customer'||v==='Debit Card'||v==='Credit Card'}
function normalizedPaymentId(v){v=String(v||'').trim();if(!v)return'';return v.replace(/^clover-payment-/i,'').replace(/^clover-manual-charge-/i,'')}
function paymentRecordIds(p){p=p||{};return[p.cloverPaymentId,p.cloverChargeId,p.paymentId,p.externalPaymentId,p.chargeId,p.id].map(normalizedPaymentId).filter(Boolean)}
function paymentRecordsShareId(a,b){var ai=paymentRecordIds(a),bi=paymentRecordIds(b);return !!(ai.length&&bi.length&&ai.some(function(id){return bi.indexOf(id)>=0}))}

function genericWheelsonPaymentNote(v){return /^WheelsonAuto\s+.*?payment$/i.test(String(v||'').trim())}
function namedPaymentMatch(p){return(db.payments||[]).find(function(x){if(x===p||weakPaymentCustomerName(x.customer))return false;if(paymentRecordsShareId(x,p))return true;return dateKeyFrom(x.date)===dateKeyFrom(p&&p.date)&&Number(x.amount||0)===Number(p&&p.amount||0)&&String(x.status||'').toLowerCase()===String(p&&p.status||'').toLowerCase()&&genericWheelsonPaymentNote(p&&p.notes||p&&p.description)})}
function descriptionCustomerName(p){var text=String(p&& (p.description||p.notes||p.memo)||'');var m=text.match(/WheelsonAuto\s+.*?payment\s+-\s+(.+)$/i);return m&&!weakPaymentCustomerName(m[1])?m[1].trim():''}
function transactionDetailText(p,customer){var text=String(p&& (p.notes||p.description)||'').trim();if(genericWheelsonPaymentNote(text))return weakPaymentCustomerName(customer)?'Clover transaction - customer name not returned':'Clover transaction';if(/^WheelsonAuto\s+.*?payment\s+-\s+/i.test(text))return 'Clover transaction';return text||String(p&&p.source||'Clover transaction')}
function attemptCustomerMatch(p,roster){var date=dateKeyFrom(p&&p.date),amount=Number(p&&p.amount||0),ids=paymentRecordIds(p),matches=[];(roster||recurringRoster()).forEach(function(r){(r.paymentAttempts||[]).forEach(function(a){var sameId=ids.length&&paymentRecordIds(a).some(function(id){return ids.indexOf(id)>=0});var sameDayAmount=date&&dateKeyFrom(a.date)===date&&amount&&Number(a.amount||0)===amount;var result=String(a.result||a.status||'').toLowerCase();if((sameId||sameDayAmount)&&(result.indexOf('paid')>=0||result.indexOf('submitted')>=0||result.indexOf('fail')>=0||result.indexOf('declin')>=0||sameId))matches.push(r)})});var seen={};matches=matches.filter(function(r){var k=normName(r.customer);if(!k||seen[k])return false;seen[k]=true;return true});return matches.length===1?matches[0]:null}
function failedRosterMatch(p,roster){if(!paymentFailed(p))return null;var amount=Number(p&&p.amount||0);var rows=(roster||recurringRoster()).filter(function(r){return amount&&Number(r.amount||0)===amount&&(todayFailureCount(r)>0||moneyTodayStatus(r))});var seen={};rows=rows.filter(function(r){var k=normName(r.customer);if(!k||seen[k])return false;seen[k]=true;return true});return rows.length===1?rows[0]:null}
function transactionCustomerName(p,roster){var raw=String(p&&p.customer||'').trim();if(!weakPaymentCustomerName(raw))return raw;roster=roster||recurringRoster();var named=namedPaymentMatch(p);if(named&&named.customer)return named.customer;var described=descriptionCustomerName(p);if(described)return described;var extCustomer=String(p&&p.externalCustomerReference||'').trim();if(extCustomer&&!/^[A-Z0-9]{8,}$/.test(extCustomer)&&!weakPaymentCustomerName(extCustomer))return extCustomer;var ids=[p&&p.recurringPaymentId,p&&p.recurringId,p&&p.cloverSubscriptionId,p&&p.subscriptionId].filter(Boolean).map(String);var r=roster.find(function(x){return ids.indexOf(String(x.id||''))>=0||ids.indexOf(String(x.cloverSubscriptionId||''))>=0});if(!r){var cid=String(p&&(p.cloverCustomerId||p.customerId)||'').trim();if(cid)r=roster.find(function(x){return String(x.cloverCustomerId||'')===cid})}if(!r&&p&&p.paymentRequestId){var req=(db.paymentRequests||[]).find(function(x){return x.id===p.paymentRequestId});if(req&&req.customer)return req.customer;if(req&&req.recurringPaymentId)r=roster.find(function(x){return x.id===req.recurringPaymentId})}if(!r&&p&&p.email)r=roster.find(function(x){return normName(x.email)===normName(p.email)});if(!r&&p&&p.phone)r=roster.find(function(x){return String(x.phone||'').replace(/\D/g,'')===String(p.phone||'').replace(/\D/g,'')});if(!r&&p&&p.vehicle)r=roster.find(function(x){return normName(x.vehicle)===normName(p.vehicle)});if(!r)r=attemptCustomerMatch(p,roster);if(!r)r=failedRosterMatch(p,roster);if(!r&&p&&Number(p.amount)){var same=roster.filter(function(x){return Number(x.amount||0)===Number(p.amount||0)});if(same.length===1)r=same[0]}return r&&r.customer?r.customer:(raw&&!weakPaymentCustomerName(raw)?raw:'Customer match needed')}

function paymentContactFor(c,r,con){return [c&&c.phone||r&&r.phone||con&&con.phone,c&&c.email||r&&r.email||con&&con.email].filter(Boolean).join(' - ')||'No contact saved'}
function paymentVehicleInfo(c,r,con,car){var vehicle=car&&car.id?vehicleName(car):(c&&c.vehicle||r&&r.vehicle||con&&con.vehicle||r&&r.plan||'No vehicle linked');var plate=car&&car.plate||car&&car.stock||c&&c.licensePlate||r&&r.licensePlate||con&&con.licensePlate||'';var temp=car&&car.tempTag||c&&c.tempTag||r&&r.tempTag||con&&con.tempTag||'';var tracker=car&&car.tracker||c&&c.tracker||r&&r.tracker||con&&con.tracker||'';var vin=car&&car.vin||c&&c.vin||r&&r.vin||con&&con.vin||'';return{vehicle:vehicle,plate:plate,temp:temp,tracker:tracker,vin:vin,line:[plate?'Plate '+plate:'',temp?'Old temp '+temp:'',tracker?'Tracker '+tracker:''].filter(Boolean).join(' | ')||'No tag/tracker saved'}}


function paymentReceiptBody(p,customer,car){var vehicle=car&&car.id?vehicleName(car):(p.vehicle||'your vehicle'),tag=car&& (car.plate||car.stock)||p.licensePlate||p.plate||'',vin=car&&car.vin||p.vin||'',ref=p.cloverPaymentId||p.externalReferenceId||p.paymentRequestId||p.id||'';return 'Hi '+(customer||'there')+', this is WheelsonAuto. Receipt for '+money(p.amount||0)+' received on '+(p.date||todayKey())+'. Method: '+(p.method||p.type||p.source||'Payment')+'. Vehicle: '+vehicle+(vin?' | VIN '+vin:'')+(tag?' | Tag '+tag:'')+(ref?' | Reference '+ref:'')+'. Thank you.'}
