function closeoutNoteForToday(){var k=todayKey();return(db.dailyCloseouts||[]).find(function(x){return x.dateKey===k})||{}}
function closeoutNoteHtml(){var n=closeoutNoteForToday();return '<div class="item closeout-note-box" style="margin-top:12px"><div class="item-row"><strong>Owner closeout notes</strong>'+badge(n.updatedAt?'Saved':'Draft','blue')+'</div><textarea id="closeoutOwnerNotes" placeholder="Example: who paid outside app, who needs a call tomorrow, cash received, Clover mismatch, repairs affecting payment...">'+esc(n.note||'')+'</textarea><div class="actions"><button class="btn primary" data-action="save-closeout-note">Save note</button><button class="btn gold" data-action="send-daily-closeout-email">Email closeout</button></div></div>'}
function attachCloseoutEmailButton(){if(!isOwner())return;var board=document.querySelector('.closeout-board');if(board&&!board.querySelector('.closeout-note-box'))board.insertAdjacentHTML('beforeend',closeoutNoteHtml());var actions=document.querySelector('.closeout-board .section-head .actions');if(actions&&!actions.querySelector('[data-action="send-daily-closeout-email"]'))actions.insertAdjacentHTML('beforeend','<button class="btn gold" data-action="send-daily-closeout-email">Email closeout</button>')}
function printDailyCloseout(){var board=document.querySelector('.closeout-board');if(!board){notify('Open Daily closeout first');return}document.body.classList.add('print-closeout-mode');setTimeout(function(){window.print();setTimeout(function(){document.body.classList.remove('print-closeout-mode')},600)},50);notify('Print closeout opened. Choose Save as PDF if you need a PDF.')}
var __woaRenderWithCloseout=render;render=function(){__woaRenderWithCloseout();attachCloseoutEmailButton()};
document.addEventListener('click',async function(e){var b=e.target.closest('button[data-action]');if(!b)return;var a=b.dataset.action;if(['send-daily-closeout-email','save-closeout-note','print-daily-closeout'].indexOf(a)<0)return;e.preventDefault();e.stopImmediatePropagation();if(a==='print-daily-closeout'){printDailyCloseout();return}if(!isOwner()){notify('Only owner can update daily closeout');return}var note=val('closeoutOwnerNotes'),k=todayKey();if(a==='save-closeout-note'){db.dailyCloseouts=db.dailyCloseouts||[];var row=db.dailyCloseouts.find(function(x){return x.dateKey===k});if(!row){row={id:'closeout-'+k,dateKey:k};db.dailyCloseouts.unshift(row)}row.note=note;row.updatedAt=new Date().toISOString();b.disabled=true;b.classList.add('is-loading');var ok=await save();b.disabled=false;b.classList.remove('is-loading');if(ok){render();notify('Closeout note saved')}else notify('Closeout note did not save');return}b.disabled=true;b.classList.add('is-loading');var result=await post('/api/notifications/daily-closeout',{ownerNote:note});b.disabled=false;b.classList.remove('is-loading');if(result.ok){await refreshData(true);view='Messages';tab='History';Messages();notify(result.sent?'Daily closeout emailed':'Daily closeout saved as email draft')}else notify(result.error||'Daily closeout email did not send')},true);
document.addEventListener('click',async function(e){var b=e.target.closest('button[data-action]');if(!b)return;var a=b.dataset.action;if(['toggle-messaging','toggle-email-messaging','toggle-star-ai','toggle-star-autosend'].indexOf(a)<0)return;e.preventDefault();e.stopImmediatePropagation();if(!isOwner()){notify('Only owner can change messaging and Star settings');return}var payload={};if(a==='toggle-messaging')payload.enabled=b.dataset.enabled==='1';if(a==='toggle-email-messaging')payload.emailEnabled=b.dataset.enabled==='1';if(a==='toggle-star-ai')payload.aiEnabled=b.dataset.enabled==='1';if(a==='toggle-star-autosend')payload.aiAutoSend=b.dataset.enabled==='1';b.disabled=true;b.classList.add('is-loading');var saved=await post('/api/messages/settings',payload);b.disabled=false;b.classList.remove('is-loading');if(saved.ok){db.integrations=db.integrations||{};db.integrations.messaging=saved.messaging||db.integrations.messaging;view='Messages';tab='Star';Messages();notify('Messaging settings updated')}else notify(saved.error||'Could not update messaging settings')},true);
